// weatherApi.js
// Calls Anthropic Claude API to generate realistic weather forecast data.
// Replace this with a real weather API (e.g. OpenWeatherMap) for production use.

const ANTHROPIC_API_KEY = process.env.REACT_APP_ANTHROPIC_API_KEY || '';
console.log("API KEY:", ANTHROPIC_API_KEY);

export async function fetchCityWeather(cityName) {
  if (!ANTHROPIC_API_KEY) {
    throw new Error(
      'Missing API key. Add REACT_APP_ANTHROPIC_API_KEY to your .env file.'
    );
  }

  const prompt = `Return ONLY a JSON object (no markdown, no extra text) for the city: "${cityName}"

Schema:
{
  "name": "city display name",
  "country": "2-letter country code",
  "current": {
    "temp": number (celsius),
    "desc": "short weather description",
    "icon": "one weather emoji",
    "humidity": number (percent),
    "wind": number (km/h)
  },
  "forecast": [
    { "day": "Mon", "date": "Jun 9",  "high": number, "low": number, "icon": "emoji", "desc": "brief" },
    { "day": "Tue", "date": "Jun 10", "high": number, "low": number, "icon": "emoji", "desc": "brief" },
    { "day": "Wed", "date": "Jun 11", "high": number, "low": number, "icon": "emoji", "desc": "brief" },
    { "day": "Thu", "date": "Jun 12", "high": number, "low": number, "icon": "emoji", "desc": "brief" },
    { "day": "Fri", "date": "Jun 13", "high": number, "low": number, "icon": "emoji", "desc": "brief" }
  ]
}

Use realistic typical seasonal weather for June. If city doesn't exist, return { "error": "City not found" }.`;

  const response = await fetch('https://api.anthropic.com/v1/messages', {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      'x-api-key': ANTHROPIC_API_KEY,
      'anthropic-version': '2023-06-01',
      'anthropic-dangerous-direct-browser-access': 'true',
    },
    body: JSON.stringify({
      model: 'claude-sonnet-4-20250514',
      max_tokens: 1000,
      messages: [{ role: 'user', content: prompt }],
    }),
  });

if (!response.ok) {
  const errText = await response.text();
  console.log("Anthropic Error:", errText);
  throw new Error(`API error: ${response.status}`);
}

  const data = await response.json();
  const text = data.content.map((b) => b.text || '').join('');
  const clean = text.replace(/```json|```/g, '').trim();

  let parsed;
  try {
    parsed = JSON.parse(clean);
  } catch {
    throw new Error('Invalid response from API');
  }

  if (parsed.error) throw new Error(parsed.error);
  return parsed;
}
